import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project_basename, framework, package_id) -> (requested, resolved)
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(pname, fw['framework'], pkg['id'])] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for key in all_keys:
    proj, fw, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv and av:
        if bv[1] != av[1]:
            changes.append((proj, fw, pkg, bv[1], av[1], 'Aligned to highest version'))
        else:
            unchanged.append((proj, fw, pkg, av[1]))
    elif bv and not av:
        changes.append((proj, fw, pkg, bv[1], '-', 'Removed'))
    elif av and not bv:
        changes.append((proj, fw, pkg, '-', av[1], 'Added'))

print('=== CHANGES ===')
if changes:
    print(f'{'Project':<16} {'Framework':<10} {'Package':<45} {'Before':<10} {'After':<10} Status')
    print('-' * 120)
    for c in changes:
        print(f'{c[0]:<16} {c[1]:<10} {c[2]:<45} {c[3]:<10} {c[4]:<10} {c[5]}')
else:
    print('No changes detected.')

print()
print('=== UNCHANGED ===')
print(f'{'Project':<16} {'Framework':<10} {'Package':<45} {'Version':<10}')
print('-' * 90)
for u in unchanged:
    print(f'{u[0]:<16} {u[1]:<10} {u[2]:<45} {u[3]:<10}')
"

